import React, { useState, useEffect } from "react";
import { Plus, X, Loader2, Trash2, MapPin, Users, Calendar } from "lucide-react";
import { supabase } from './lib/supabase';

export function ScheduleManager() {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [classes, setClasses] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Estados del formulario
  const [title, setTitle] = useState('');
  const [trainer, setTrainer] = useState('');
  const [date, setDate] = useState('');
  const [time, setTime] = useState('08:00');
  const [duration, setDuration] = useState('60'); // minutos
  const [maxCapacity, setMaxCapacity] = useState('20');
  const [location, setLocation] = useState('Zona Principal');
  const [intensityBadge, setIntensityBadge] = useState('Media');

  // Configuración del calendario
  const weekDays = ["Lun", "Mar", "Mié", "Jue", "Vie", "Sáb", "Dom"];
  const startHour = 8;
  const totalHours = 14; // De 8:00 a 22:00

  // Obtener fechas de la semana actual
  const getWeekDates = () => {
    const today = new Date();
    // Ajustar para que el lunes sea el primer día de la semana
    const dayOfWeek = today.getDay() === 0 ? 6 : today.getDay() - 1; 
    const monday = new Date(today);
    monday.setDate(today.getDate() - dayOfWeek);
    monday.setHours(0, 0, 0, 0);

    const dates = [];
    for (let i = 0; i < 7; i++) {
      const date = new Date(monday);
      date.setDate(monday.getDate() + i);
      dates.push(date);
    }
    return dates;
  };

  const weekDates = getWeekDates();
  const weekStart = weekDates[0];
  const weekEnd = new Date(weekDates[6]);
  weekEnd.setHours(23, 59, 59, 999);

  // Cargar clases de esta semana
  const fetchClasses = async () => {
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from('classes')
        .select('*')
        .gte('start_time', weekStart.toISOString())
        .lte('start_time', weekEnd.toISOString());

      if (error) throw error;
      setClasses(data || []);
    } catch (error) {
      console.error("Error cargando clases:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchClasses();
  }, []);

  // Crear nueva clase
  const handleCreateClass = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    try {
      const startDateTime = new Date(`${date}T${time}:00`);
      const endDateTime = new Date(startDateTime.getTime() + parseInt(duration) * 60000);

      const { error } = await supabase.from('classes').insert([
        {
          title,
          trainer,
          start_time: startDateTime.toISOString(),
          end_time: endDateTime.toISOString(),
          max_capacity: parseInt(maxCapacity),
          location,
          intensity_badge: intensityBadge,
        }
      ]);

      if (error) throw error;

      setIsModalOpen(false);
      setTitle('');
      setTrainer('');
      setDate('');
      setTime('08:00');
      fetchClasses();

    } catch (error: any) {
      alert("Error al crear la clase: " + error.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  // Eliminar clase
  const handleDeleteClass = async (id: string, classTitle: string, e: React.MouseEvent) => {
    e.stopPropagation(); // Evitar que el click se propague si hacemos la celda clickeable en el futuro
    if (window.confirm(`¿Cancelar la clase de ${classTitle}?`)) {
      try {
        const { error } = await supabase.from('classes').delete().eq('id', id);
        if (error) throw error;
        fetchClasses();
      } catch (error: any) {
        alert("Error al eliminar: " + error.message);
      }
    }
  };

  // Función auxiliar para colocar la clase en la cuadrícula
  const getClassForSlot = (dayIndex: number, hour: number) => {
    const targetDate = weekDates[dayIndex].toISOString().split('T')[0];

    return classes.filter(cls => {
      const clsDate = new Date(cls.start_time);
      const clsDateString = clsDate.toISOString().split('T')[0];
      const clsHour = clsDate.getHours();

      return clsDateString === targetDate && clsHour === hour;
    });
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold text-white tracking-tight">Calendario Semanal</h1>
          <p className="text-gray-400 mt-1">
            Semana del {weekStart.toLocaleDateString('es-ES', { day: 'numeric', month: 'short' })} al {weekDates[6].toLocaleDateString('es-ES', { day: 'numeric', month: 'short' })}
          </p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)} 
          className="bg-[#39FF14] text-black px-6 py-3 rounded-xl font-bold flex items-center gap-2 hover:bg-[#2EE010] shadow-[0_0_15px_rgba(57,255,20,0.2)] hover:shadow-[0_0_20px_rgba(57,255,20,0.4)] transition-all"
        >
          <Plus size={20} /> Nueva Clase
        </button>
      </div>

      <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-2xl overflow-hidden shadow-xl">
        {/* Cabecera del calendario */}
        <div className="grid grid-cols-8 border-b border-[#2a2a2a] bg-[#121212]">
          <div className="p-4 border-r border-[#2a2a2a] text-xs text-gray-500 flex items-center justify-center font-bold tracking-wider uppercase">Hora</div>
          {weekDays.map((day, index) => (
            <div key={day} className="p-4 text-center border-r border-[#2a2a2a] last:border-r-0 flex flex-col items-center justify-center">
              <span className="font-bold text-sm text-white">{day}</span>
              <span className="text-xs text-[#39FF14] font-medium mt-1">{weekDates[index].getDate()}</span>
            </div>
          ))}
        </div>

        {/* Cuerpo del calendario */}
        <div className="relative">
          {loading && (
            <div className="absolute inset-0 bg-[#1a1a1a]/80 backdrop-blur-sm z-10 flex items-center justify-center">
              <Loader2 className="w-8 h-8 text-[#39FF14] animate-spin" />
            </div>
          )}

          {[...Array(totalHours)].map((_, i) => {
            const currentHour = i + startHour;
            return (
              <div key={i} className="grid grid-cols-8 border-b border-[#2a2a2a] min-h-[100px] last:border-b-0">
                {/* Columna de hora */}
                <div className="p-2 border-r border-[#2a2a2a] bg-[#121212]/50">
                  <span className="text-xs font-bold text-gray-500 bg-[#1a1a1a] px-2 py-1 rounded-md border border-[#2a2a2a]">
                    {currentHour.toString().padStart(2, '0')}:00
                  </span>
                </div>

                {/* Celdas de días */}
                {[...Array(7)].map((_, dayIndex) => {
                  const classesInSlot = getClassForSlot(dayIndex, currentHour);

                  return (
                    <div key={dayIndex} className="border-r border-[#2a2a2a] last:border-r-0 hover:bg-[#39FF14]/5 transition-colors p-1 relative">
                      {classesInSlot.map((cls, idx) => {
                        const startMin = new Date(cls.start_time).getMinutes();
                        const durationMin = (new Date(cls.end_time).getTime() - new Date(cls.start_time).getTime()) / 60000;

                        // Calculamos posición visual (simplificado, asume clases dentro de la hora)
                        const topOffset = `${(startMin / 60) * 100}%`;
                        const height = durationMin > 60 ? '100%' : `${(durationMin / 60) * 100}%`;

                        return (
                          <div 
                            key={cls.id} 
                            className="bg-[#39FF14]/10 border border-[#39FF14]/30 rounded-lg p-2 group relative hover:bg-[#39FF14]/20 transition-colors cursor-pointer mt-1"
                            style={{ minHeight: '80px' }}
                          >
                            <button 
                              onClick={(e) => handleDeleteClass(cls.id, cls.title, e)}
                              className="absolute top-1 right-1 opacity-0 group-hover:opacity-100 p-1 bg-black/50 rounded text-red-400 hover:text-red-500 hover:bg-black transition-all"
                            >
                              <Trash2 size={12} />
                            </button>
                            <div className="text-[10px] font-bold text-[#39FF14] mb-1">
                              {new Date(cls.start_time).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                            </div>
                            <div className="text-xs font-bold text-white leading-tight mb-1 truncate" title={cls.title}>{cls.title}</div>
                            <div className="text-[10px] text-gray-400 truncate flex items-center gap-1">
                              <Users size={10} className="shrink-0"/> {cls.trainer}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  );
                })}
              </div>
            );
          })}
        </div>
      </div>

      {/* Modal de Creación */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-[#121212] border border-[#2a2a2a] w-full max-w-xl rounded-3xl p-8 relative shadow-2xl animate-in zoom-in-95 duration-200">
            <button onClick={() => setIsModalOpen(false)} className="absolute top-6 right-6 text-gray-400 hover:text-white transition-colors">
              <X size={24} />
            </button>
            <h2 className="text-2xl font-bold mb-6 text-white flex items-center gap-2">
              <Calendar className="text-[#39FF14]" /> Nueva Sesión
            </h2>

            <form onSubmit={handleCreateClass} className="space-y-5">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-xs text-gray-500 uppercase font-bold tracking-wider mb-1 block">Nombre de la clase</label>
                  <input required value={title} onChange={e => setTitle(e.target.value)} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl text-white focus:border-[#39FF14] outline-none transition-colors" placeholder="Ej: CrossFit WOD" />
                </div>
                <div>
                  <label className="text-xs text-gray-500 uppercase font-bold tracking-wider mb-1 block">Entrenador</label>
                  <input required value={trainer} onChange={e => setTrainer(e.target.value)} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl text-white focus:border-[#39FF14] outline-none transition-colors" placeholder="Ej: Marcos Silva" />
                </div>
              </div>

              <div className="grid grid-cols-3 gap-4 border-y border-[#2a2a2a] py-5">
                <div>
                  <label className="text-xs text-gray-500 uppercase font-bold tracking-wider mb-1 block">Fecha</label>
                  <input type="date" required value={date} onChange={e => setDate(e.target.value)} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl text-white focus:border-[#39FF14] outline-none [color-scheme:dark]" />
                </div>
                <div>
                  <label className="text-xs text-gray-500 uppercase font-bold tracking-wider mb-1 block">Hora</label>
                  <input type="time" required value={time} onChange={e => setTime(e.target.value)} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl text-white focus:border-[#39FF14] outline-none [color-scheme:dark]" />
                </div>
                <div>
                  <label className="text-xs text-gray-500 uppercase font-bold tracking-wider mb-1 block">Duración</label>
                  <select value={duration} onChange={e => setDuration(e.target.value)} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl text-white focus:border-[#39FF14] outline-none appearance-none">
                    <option value="30">30 min</option>
                    <option value="45">45 min</option>
                    <option value="60">1 hora</option>
                    <option value="90">1.5 horas</option>
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                 <div>
                  <label className="text-xs text-gray-500 uppercase font-bold tracking-wider mb-1 block">Capacidad</label>
                  <input type="number" required min="1" value={maxCapacity} onChange={e => setMaxCapacity(e.target.value)} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl text-white focus:border-[#39FF14] outline-none" />
                </div>
                <div>
                  <label className="text-xs text-gray-500 uppercase font-bold tracking-wider mb-1 block">Intensidad</label>
                  <select value={intensityBadge} onChange={e => setIntensityBadge(e.target.value)} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl text-white focus:border-[#39FF14] outline-none appearance-none">
                    <option value="Baja">Baja</option>
                    <option value="Media">Media</option>
                    <option value="Alta">Alta</option>
                  </select>
                </div>
              </div>

              <button disabled={isSubmitting} className="w-full bg-[#39FF14] text-black font-bold py-4 rounded-xl mt-6 hover:bg-[#2EE010] transition-colors flex items-center justify-center gap-2">
                {isSubmitting ? <Loader2 className="animate-spin w-5 h-5" /> : 'Guardar en Calendario'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
